# Vitest Setup

```bash
npm install -D vitest @vitest/coverage-v8
# For React:
npm install -D @testing-library/react @testing-library/user-event jsdom
```

## vitest.config.ts
```ts
import { defineConfig } from 'vitest/config';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    environment: 'jsdom',
    globals: true,          // no need to import describe/it/expect
    setupFiles: ['./src/test/setup.ts'],
    coverage: {
      provider: 'v8',
      reporter: ['text', 'lcov', 'html'],
      thresholds: { lines: 80, functions: 80, branches: 70 },
      exclude: ['node_modules', '*.config.*', 'src/test'],
    },
  },
});
```

## package.json scripts
```json
{
  "scripts": {
    "test": "vitest",
    "test:run": "vitest run",
    "test:coverage": "vitest run --coverage",
    "test:ui": "vitest --ui"
  }
}
```

## setup.ts
```ts
import '@testing-library/jest-dom';
// global setup: mocks, env vars, etc.
```

## Basic Test
```ts
import { describe, it, expect, vi } from 'vitest';
import { formatDate } from '../utils/date';

describe('formatDate', () => {
  it('formats ISO string to locale date', () => {
    expect(formatDate('2024-01-15')).toBe('Jan 15, 2024');
  });

  it('returns empty string for null', () => {
    expect(formatDate(null)).toBe('');
  });
});
```

## Key Advantages over Jest
- Native ESM — no transform config
- Native TypeScript — no ts-jest
- ~5-10x faster hot reload
- Identical API to Jest (`vi.*` = `jest.*`)

# @testing-library/react

```bash
npm install -D @testing-library/react @testing-library/user-event @testing-library/jest-dom
```

## Query Priority (high → low confidence)
1. `getByRole` — best (matches accessible tree)
2. `getByLabelText` — forms
3. `getByPlaceholderText` — fallback for inputs
4. `getByText` — buttons, headings
5. `getByTestId` — last resort (`data-testid`)

## Component Test Example
```tsx
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { LoginForm } from './LoginForm';

describe('LoginForm', () => {
  it('shows error for invalid email', async () => {
    const user = userEvent.setup();
    render(<LoginForm onSubmit={vi.fn()} />);

    await user.type(screen.getByLabelText('Email'), 'not-an-email');
    await user.click(screen.getByRole('button', { name: /sign in/i }));

    expect(screen.getByText('Invalid email')).toBeInTheDocument();
  });

  it('calls onSubmit with valid credentials', async () => {
    const user = userEvent.setup();
    const onSubmit = vi.fn();
    render(<LoginForm onSubmit={onSubmit} />);

    await user.type(screen.getByLabelText('Email'), 'user@example.com');
    await user.type(screen.getByLabelText('Password'), 'password123');
    await user.click(screen.getByRole('button', { name: /sign in/i }));

    expect(onSubmit).toHaveBeenCalledWith({ email: 'user@example.com', password: 'password123' });
  });
});
```

## Async State Updates
```tsx
import { waitFor, findByText } from '@testing-library/react';

// findBy* = getBy* + waitFor
const successMsg = await screen.findByText('Saved!');

// waitFor explicit assertion
await waitFor(() => {
  expect(screen.getByRole('status')).toHaveTextContent('Done');
});
```

## Avoid
- `container.querySelector('.class')` — ties tests to implementation
- Testing state directly — test behavior visible to the user
- `act()` manually — userEvent handles it

# Mock Service Worker (MSW)

```bash
npm install -D msw
npx msw init public/ --save  # for browser usage
```

## Define Handlers
```ts
// src/mocks/handlers.ts
import { http, HttpResponse } from 'msw';

export const handlers = [
  http.get('/api/users', () => {
    return HttpResponse.json([
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ]);
  }),

  http.post('/api/users', async ({ request }) => {
    const body = await request.json();
    return HttpResponse.json({ id: 3, ...body }, { status: 201 });
  }),

  http.get('/api/users/:id', ({ params }) => {
    if (params.id === '999') {
      return new HttpResponse(null, { status: 404 });
    }
    return HttpResponse.json({ id: params.id, name: 'User' });
  }),
];
```

## Test Setup (Node / Vitest)
```ts
// src/test/setup.ts
import { setupServer } from 'msw/node';
import { handlers } from '../mocks/handlers';

const server = setupServer(...handlers);

beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());
```

## Override Handler per Test
```ts
it('shows error when API fails', async () => {
  server.use(
    http.get('/api/users', () => new HttpResponse(null, { status: 500 })),
  );
  render(<UserList />);
  expect(await screen.findByText('Something went wrong')).toBeInTheDocument();
});
```

## Browser Setup (Storybook / Dev)
```ts
// src/mocks/browser.ts
import { setupWorker } from 'msw/browser';
import { handlers } from './handlers';
export const worker = setupWorker(...handlers);

// main.tsx
if (process.env.NODE_ENV === 'development') {
  const { worker } = await import('./mocks/browser');
  await worker.start();
}
```

# Playwright E2E

```bash
npm install -D @playwright/test
npx playwright install chromium  # or: chromium firefox webkit
```

## playwright.config.ts
```ts
import { defineConfig, devices } from '@playwright/test';

export default defineConfig({
  testDir: './e2e',
  fullyParallel: true,
  retries: process.env.CI ? 2 : 0,
  reporter: [['html', { open: 'never' }]],
  use: {
    baseURL: 'http://localhost:3000',
    trace: 'on-first-retry',
    screenshot: 'only-on-failure',
  },
  projects: [
    { name: 'chromium', use: { ...devices['Desktop Chrome'] } },
    { name: 'Mobile', use: { ...devices['iPhone 14'] } },
  ],
  webServer: {
    command: 'npm run dev',
    url: 'http://localhost:3000',
    reuseExistingServer: !process.env.CI,
  },
});
```

## Test Examples
```ts
// e2e/auth.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Authentication', () => {
  test('user can sign in', async ({ page }) => {
    await page.goto('/login');
    await page.getByLabel('Email').fill('user@example.com');
    await page.getByLabel('Password').fill('password123');
    await page.getByRole('button', { name: 'Sign in' }).click();

    await expect(page).toHaveURL('/dashboard');
    await expect(page.getByRole('heading', { name: 'Dashboard' })).toBeVisible();
  });

  test('shows error for invalid credentials', async ({ page }) => {
    await page.goto('/login');
    await page.getByLabel('Email').fill('wrong@example.com');
    await page.getByLabel('Password').fill('wrongpass');
    await page.getByRole('button', { name: 'Sign in' }).click();

    await expect(page.getByText('Invalid email or password')).toBeVisible();
  });
});
```

## Page Object Model (for complex flows)
```ts
class LoginPage {
  constructor(private page: Page) {}

  async goto() { await this.page.goto('/login'); }
  async login(email: string, password: string) {
    await this.page.getByLabel('Email').fill(email);
    await this.page.getByLabel('Password').fill(password);
    await this.page.getByRole('button', { name: 'Sign in' }).click();
  }
}
```

## Run Commands
```bash
npx playwright test              # headless
npx playwright test --headed     # watch browser
npx playwright test --ui         # interactive UI mode
npx playwright show-report       # HTML report
```

# Testing Custom Hooks

```ts
import { renderHook, act } from '@testing-library/react';
import { useCounter } from './useCounter';

describe('useCounter', () => {
  it('initializes with default value', () => {
    const { result } = renderHook(() => useCounter());
    expect(result.current.count).toBe(0);
  });

  it('increments count', () => {
    const { result } = renderHook(() => useCounter(5));

    act(() => result.current.increment());

    expect(result.current.count).toBe(6);
  });

  it('resets to initial value', () => {
    const { result } = renderHook(() => useCounter(10));

    act(() => {
      result.current.increment();
      result.current.reset();
    });

    expect(result.current.count).toBe(10);
  });
});
```

## Hooks with Context
```ts
const wrapper = ({ children }: { children: React.ReactNode }) => (
  <AuthProvider>{children}</AuthProvider>
);

const { result } = renderHook(() => useAuth(), { wrapper });
```

## Hooks with Async State (TanStack Query)
```ts
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';

const createWrapper = () => {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } },
  });
  return ({ children }) => (
    <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  );
};

const { result } = renderHook(() => useUsers(), { wrapper: createWrapper() });
await waitFor(() => expect(result.current.isSuccess).toBe(true));
expect(result.current.data).toHaveLength(2);
```

## act() Rules
- Wrap state updates in `act()` — Vitest/Testing Library warns if you forget
- `userEvent` auto-wraps in act
- `renderHook` result stays current — no need to destructure inside each test

# Accessibility Testing

## jest-axe (Unit/Component Level)
```bash
npm install -D jest-axe
```

```ts
import { render } from '@testing-library/react';
import { axe, toHaveNoViolations } from 'jest-axe';
import { expect } from 'vitest';

expect.extend(toHaveNoViolations);

it('has no accessibility violations', async () => {
  const { container } = render(<LoginForm onSubmit={vi.fn()} />);
  const results = await axe(container);
  expect(results).toHaveNoViolations();
});
```

## Playwright Accessibility Snapshot
```ts
import { test, expect } from '@playwright/test';

test('homepage accessibility', async ({ page }) => {
  await page.goto('/');

  // Snapshot the accessibility tree
  await expect(page).toHaveScreenshot('homepage.png');  // visual

  // Check ARIA roles and labels
  const nav = page.getByRole('navigation');
  await expect(nav).toBeVisible();

  // Keyboard navigation
  await page.keyboard.press('Tab');
  const focused = page.locator(':focus');
  await expect(focused).toBeVisible();
});
```

## Playwright with axe-playwright
```bash
npm install -D axe-playwright
```
```ts
import { checkA11y, injectAxe } from 'axe-playwright';

test('no a11y violations on login page', async ({ page }) => {
  await page.goto('/login');
  await injectAxe(page);
  await checkA11y(page, '#main-content', {
    axeOptions: { rules: { 'color-contrast': { enabled: true } } },
  });
});
```

## Common Violations to Test
- Missing `alt` on images
- Form inputs without labels
- Buttons without accessible names
- Missing `lang` on `<html>`
- Insufficient color contrast (4.5:1 for normal text)
- No skip-to-content link
- Focus not visible (`:focus-visible` required)

# Visual Regression with Playwright

## Snapshot Test
```ts
import { test, expect } from '@playwright/test';

test('homepage matches snapshot', async ({ page }) => {
  await page.goto('/');
  // First run: creates reference image in __snapshots__
  // Subsequent runs: compares against reference
  await expect(page).toHaveScreenshot('homepage.png', {
    maxDiffPixelRatio: 0.02,  // allow 2% pixel diff
    threshold: 0.2,           // color threshold per pixel
  });
});

test('button states', async ({ page }) => {
  await page.goto('/components');
  const button = page.getByRole('button', { name: 'Submit' });

  await expect(button).toHaveScreenshot('button-default.png');

  await button.hover();
  await expect(button).toHaveScreenshot('button-hover.png');
});
```

## playwright.config.ts for Visual Tests
```ts
export default defineConfig({
  expect: {
    toHaveScreenshot: {
      mode: 'css',          // render mode
      animations: 'disabled', // disable CSS animations for stable snapshots
    },
  },
});
```

## Update Snapshots
```bash
npx playwright test --update-snapshots
```

## Dark Mode Visual Test
```ts
test('dark mode homepage', async ({ page }) => {
  await page.emulateMedia({ colorScheme: 'dark' });
  await page.goto('/');
  await expect(page).toHaveScreenshot('homepage-dark.png');
});
```

## Mobile Responsive
```ts
test('mobile layout', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('/');
  await expect(page).toHaveScreenshot('homepage-mobile.png');
});
```

## CI Workflow Note
Commit `__snapshots__/` directory. On CI, if snapshots differ, the test fails and uploads the diff as an artifact.

# Vitest Mocks (vi.*)

## Function Mocks
```ts
const sendEmail = vi.fn();
sendEmail.mockResolvedValue({ sent: true });

await sendEmail('user@example.com');

expect(sendEmail).toHaveBeenCalledOnce();
expect(sendEmail).toHaveBeenCalledWith('user@example.com');
```

## Module Mocks
```ts
// Mock entire module
vi.mock('@/lib/email', () => ({
  sendEmail: vi.fn().mockResolvedValue({ sent: true }),
  sendSMS: vi.fn(),
}));

// Partial mock (keep real implementation, override one function)
vi.mock('@/lib/auth', async (importOriginal) => {
  const actual = await importOriginal<typeof import('@/lib/auth')>();
  return { ...actual, verifyToken: vi.fn().mockResolvedValue({ userId: '1' }) };
});
```

## Spy (track calls without replacing)
```ts
const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

render(<ErrorBoundary><BrokenComponent /></ErrorBoundary>);

expect(consoleSpy).toHaveBeenCalled();
consoleSpy.mockRestore();
```

## Timer Mocks
```ts
beforeEach(() => vi.useFakeTimers());
afterEach(() => vi.useRealTimers());

it('debounce fires after 300ms', () => {
  const handler = vi.fn();
  const debounced = debounce(handler, 300);

  debounced();
  expect(handler).not.toHaveBeenCalled();

  vi.advanceTimersByTime(300);
  expect(handler).toHaveBeenCalledOnce();
});
```

## Environment Variable Mocking
```ts
it('uses API key from env', () => {
  const originalEnv = process.env.API_KEY;
  process.env.API_KEY = 'test-key';

  const client = createApiClient();
  expect(client.key).toBe('test-key');

  process.env.API_KEY = originalEnv;  // restore
});
```

## Cleanup (critical)
```ts
afterEach(() => {
  vi.clearAllMocks();   // reset call counts
  // vi.resetAllMocks() // also reset implementations
  // vi.restoreAllMocks() // restore spied-on originals
});
```
